import React from "react";
import CounterItem from "./counter-item";
import { schoolData } from "@/data/schoolData";

export default function CounterOne() {
  const { stats } = schoolData;
  
  return (
    <section className="counter-area tp-counter-wrap mb-90">
      <div className="container">
        <div
          className="tp-counter-bg wow fadeInUp"
          data-wow-delay=".3s"
          data-background="assets/img/bg/counter-bg.jpg"
          style={{ backgroundImage: `url(/assets/img/bg/counter-bg.jpg)`, backgroundColor: '#1A3C6E' }}
        >
          <div className="row">
            {stats.map((item, index) => (
            <div key={index} className="col-lg-3 col-md-6">
              <div className="tp-counter-item text-center">
                <h3 className="tp-counter-count mb-10">
                  <CounterItem min={0} max={item.value}/>
                  {item.suffix}
                </h3>
                <p>{item.label}</p>
              </div>
            </div>
            ))}
          </div>
        </div>
      </div>
    </section>
  );
}
